import { useMemo } from "react";
export function useMappedEvents(events, params) {
    return useMemo(() => {
        return Object.fromEntries(Object.entries(events ?? {}).map(([key, ev]) => {
            const evName = `on${key[0].toUpperCase()}${key.slice(1)}`;
            return [evName, (e) => ev({ event: e, ...params })];
        }));
        // This is technically fine
        // eslint-disable-next-line react-hooks/use-memo, react-hooks/exhaustive-deps
    }, [...Object.values(params), events]);
}
